/**
 * MedX aria accessibility runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * ARIA role and attribute helpers.
 */
const ARIA_TOKENS = Object.freeze({
  primary: { value: "a11y-aria-primary", scope: "a11y" },
  secondary: { value: "a11y-aria-secondary", scope: "a11y" },
  muted: { value: "a11y-aria-muted", scope: "a11y" },
  accent: { value: "a11y-aria-accent", scope: "a11y" },
  surface: { value: "a11y-aria-surface", scope: "a11y" },
});

const ARIA_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const ARIA_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const ariaRegistry = new Map();
const ARIA_listeners = new Set();
let ARIA_seq = 0;

function createAriaId(prefix = "medx-a11y-aria") {
  ARIA_seq += 1;
  return `${prefix}-${ARIA_seq}`;
}

function registerAria(config = {}) {
  const entryId = config.id ?? createAriaId();
  const preset = ARIA_PRESETS[config.preset ?? "default"] ?? ARIA_PRESETS.default;
  const token = ARIA_TOKENS[config.token ?? preset.token] ?? ARIA_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: ARIA_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  ariaRegistry.set(entryId, entry);
  notifyAriaListeners("register", entry);
  return entry;
}

function updateAria(id, patch = {}) {
  const entry = ariaRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyAriaListeners("update", entry);
  return entry;
}

function resolveAria(id) {
  const entry = ariaRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listAriaEntries(filter = {}) {
  let items = Array.from(ariaRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onAriaEvent(listener) {
  ARIA_listeners.add(listener);
  return () => ARIA_listeners.delete(listener);
}

function notifyAriaListeners(type, entry) {
  for (const listener of ARIA_listeners) {
    try {
      listener({ type, entry, registrySize: ariaRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:a11y:aria] listener error", err.message);
    }
  }
}

function getAriaMetrics() {
  const items = listAriaEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(ARIA_TOKENS).length,
    presets: Object.keys(ARIA_PRESETS).length,
  };
}

async function runMedxAria() {
  console.log("[medx:ui:a11y:aria] runtime initialized");
  console.log(`[medx:ui:a11y:aria] tokens=${Object.keys(ARIA_TOKENS).length} presets=${Object.keys(ARIA_PRESETS).length}`);

  const events = [];
  onAriaEvent((e) => events.push(e.type));

  const domains = Object.keys(ARIA_SUPPLY_CHAIN);
  const presets = Object.keys(ARIA_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerAria({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "a11y/aria" },
    });
  }

  const first = listAriaEntries()[0];
  if (first) updateAria(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getAriaMetrics();
  const resolved = first ? resolveAria(first.id) : null;

  console.log(`[medx:ui:a11y:aria] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:a11y:aria] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:a11y:aria] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:a11y:aria] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:a11y:aria] bootstrap complete");
}

module.exports = runMedxAria;
